我在 Taro 小程序里用 NutUI 做了一个 Toast，但点击按钮后什么都没有显示。下面是我的代码，帮我找出问题并修复：

import { View, Text } from '@tarojs/components'
import { Button, Toast } from '@nutui/nutui-react'
import styles from './index.module.scss'

export default function ProductPage() {
  const handleAddCart = () => {
    Toast.show({ content: '已加入购物车', icon: 'success' })
  }

  return (
    <View className={styles.page}>
      <Text className={styles.title}>商品详情</Text>
      <Button type='primary' onClick={handleAddCart}>加入购物车</Button>
    </View>
  )
}

我的 Taro 小程序 Zustand store 用了 persist 做持久化，但每次关闭小程序重新打开，token 都变成 null 了，感觉没有被正确存储。下面是我的 store 代码，帮我找出问题并修复：

import { create } from 'zustand'
import { persist, createJSONStorage } from 'zustand/middleware'

interface AuthState {
  token: string | null
  userId: string | null
  setToken: (token: string) => void
  logout: () => void
}

export const useAuthStore = create<AuthState>()(
  persist(
    (set) => ({
      token: null,
      userId: null,
      setToken: (token) => set({ token }),
      logout: () => set({ token: null, userId: null }),
    }),
    {
      name: 'auth-storage',
      storage: createJSONStorage(() => localStorage),
    }
  )
)
